from pathlib import Path
from collections import defaultdict

if __name__ == "__main__":
    d = defaultdict(int)
    for file in Path('cov').iterdir():
        with open(file) as f:
            for line in f.readlines():
                if weh := list(filter(bool, line.strip().split(' '))):
                    _, count, tag = weh
                    if 'opt_expr' in tag:
                        d[tag] += int(count)
    # print(d)
    print([k for k,v in d.items() if v==0])
